const featureDescription = $input.first().json.featureDescription || '';
const additionalContext = $input.first().json.additionalContext || '';

const systemPrompt = `You are a senior software architect performing technical analysis for a development team.

Given the following feature description, produce a detailed technical analysis as a JSON object.

## Feature Description
${featureDescription}

## Additional Context
${additionalContext}

## Output Format

Respond ONLY with valid JSON matching this schema:

{
  "title": "Short descriptive title",
  "summary": "2-3 sentence executive summary",
  "architecture": {
    "overview": "High-level architecture description",
    "components": [{"name": "...", "type": "frontend|backend|database|infrastructure", "description": "...", "changes": "..."}],
    "dataFlow": "Data flow description"
  },
  "apiContracts": [{"method": "GET|POST|PUT|DELETE", "path": "/api/...", "description": "...", "requestBody": {}, "responseBody": {}, "statusCodes": ["200 - OK"]}],
  "databaseChanges": [{"type": "new-table|alter-table", "entity": "...", "description": "...", "fields": [{"name": "...", "type": "...", "nullable": false}]}],
  "edgeCases": [{"scenario": "...", "impact": "low|medium|high", "mitigation": "..."}],
  "securityConsiderations": ["..."],
  "testingStrategy": {"unitTests": ["..."], "integrationTests": ["..."], "e2eTests": ["..."]},
  "tasks": [{"type": "epic|story|subtask", "summary": "...", "description": "...", "component": "frontend|backend|database|devops|testing", "estimate": "XS|S|M|L|XL", "priority": "Critical|High|Medium|Low", "acceptanceCriteria": ["Given X, when Y, then Z"]}],
  "estimatedComplexity": "low|medium|high",
  "suggestedApproach": "Recommended implementation order"
}

Rules: Tasks should be 1-3 day work items. Include Gherkin acceptance criteria. Be specific, not generic.`;

const model = $env.AI_MODEL || 'anthropic/claude-opus-4.6';
const maxTokens = parseInt($env.AI_MAX_TOKENS || '4096', 10);
const authHeader = 'Bearer ' + ($env.GITHUB_TOKEN || '');

const requestBody = {
  model,
  max_tokens: maxTokens,
  messages: [{ role: 'user', content: systemPrompt }]
};

return [{ json: { requestBody, authHeader, featureDescription, additionalContext } }];

const response = $input.first().json;
const content = response.choices[0].message.content;

let jsonStr = content;
if (content.includes('```json')) {
  jsonStr = content.split('```json')[1].split('```')[0].trim();
} else if (content.includes('```')) {
  jsonStr = content.split('```')[1].split('```')[0].trim();
}

let analysis;
try {
  analysis = JSON.parse(jsonStr);
} catch (e) {
  throw new Error(`Failed to parse AI response as JSON: ${e.message}\n\nRaw response: ${content.substring(0, 500)}`);
}

const vars = $('Set Variables').first().json;

return [{ json: { analysis, featureDescription: vars.featureDescription } }];

const { analysis } = $input.first().json;
const date = new Date().toISOString().split('T')[0];

let md = '';
md += `# ${analysis.title}

`;
md += `> Generated on ${date} by [ai-confluence-pipeline](https://github.com/openmindednewby/ai-confluence-pipeline)

`;
md += `**Complexity:** ${analysis.estimatedComplexity} | **Approach:** ${analysis.suggestedApproach}

`;
md += `---

`;
md += `## Summary

${analysis.summary}

`;
md += `## Architecture

${analysis.architecture.overview}

`;
md += `### Components

`;
md += `| Component | Type | Description | Changes |
`;
md += `|-----------|------|-------------|---------|
`;
for (const c of analysis.architecture.components || []) {
  md += `| **${c.name}** | \`${c.type}\` | ${c.description} | ${c.changes} |
`;
}
md += `
`;
if (analysis.architecture.dataFlow) md += `### Data Flow

${analysis.architecture.dataFlow}

`;
if (analysis.apiContracts?.length) {
  md += `## API Contracts

`;
  for (const api of analysis.apiContracts) {
    md += `### \`${api.method} ${api.path}\`

${api.description}

`;
    if (api.requestBody && Object.keys(api.requestBody).length) md += `**Request:**
\`\`\`json
${JSON.stringify(api.requestBody, null, 2)}
\`\`\`

`;
    if (api.responseBody && Object.keys(api.responseBody).length) md += `**Response:**
\`\`\`json
${JSON.stringify(api.responseBody, null, 2)}
\`\`\`

`;
    if (api.statusCodes?.length) md += `**Status Codes:** ${api.statusCodes.join(', ')}

`;
  }
}
if (analysis.databaseChanges?.length) {
  md += `## Database Changes

| Type | Entity | Description |
|------|--------|-------------|
`;
  for (const db of analysis.databaseChanges) {
    md += `| \`${db.type}\` | **${db.entity}** | ${db.description} |
`;
    if (db.fields?.length) {
      md += `
| Field | Type | Nullable | Description |
|-------|------|----------|-------------|
`;
      for (const f of db.fields) md += `| \`${f.name}\` | \`${f.type}\` | ${f.nullable ? 'Yes' : 'No'} | ${f.description || ''} |
`;
    }
  }
  md += `
`;
}
if (analysis.edgeCases?.length) {
  md += `## Edge Cases

| Scenario | Impact | Mitigation |
|----------|--------|------------|
`;
  for (const ec of analysis.edgeCases) md += `| ${ec.scenario} | \`${ec.impact}\` | ${ec.mitigation} |
`;
  md += `
`;
}
if (analysis.securityConsiderations?.length) {
  md += `## Security Considerations

`;
  for (const s of analysis.securityConsiderations) md += `- ${s}
`;
  md += `
`;
}
if (analysis.testingStrategy) {
  md += `## Testing Strategy

`;
  const ts = analysis.testingStrategy;
  if (ts.unitTests?.length) { md += `### Unit Tests
`; for (const t of ts.unitTests) md += `- ${t}
`; md += `
`; }
  if (ts.integrationTests?.length) { md += `### Integration Tests
`; for (const t of ts.integrationTests) md += `- ${t}
`; md += `
`; }
  if (ts.e2eTests?.length) { md += `### E2E Tests
`; for (const t of ts.e2eTests) md += `- ${t}
`; md += `
`; }
}
if (analysis.tasks?.length) {
  md += `## Task Breakdown

| Type | Summary | Component | Estimate | Priority |
|------|---------|-----------|----------|----------|
`;
  for (const t of analysis.tasks) md += `| \`${t.type}\` | ${t.summary} | \`${t.component}\` | ${t.estimate} | ${t.priority} |
`;
  md += `
### Task Details

`;
  for (let i = 0; i < analysis.tasks.length; i++) {
    const t = analysis.tasks[i];
    md += `#### ${i + 1}. ${t.summary}

${t.description}

`;
    if (t.acceptanceCriteria?.length) { md += `**Acceptance Criteria:**
`; for (const ac of t.acceptanceCriteria) md += `- ${ac}
`; md += `
`; }
  }
}

return [{ json: { success: true, title: analysis.title, markdown: md, analysis } }];
